#include <bits/stdc++.h>
using namespace std;
int n,m,head=1,nxt[100005],pre[100005];
bool out[100005];
int main(){
    scanf("%d",&n);
    for(int i=2;i<=n;i++){
        int k,p;
        scanf("%d%d",&k,&p);
        if(k==head && p==0)
            head=i;
        if(p==0){
            pre[i]=pre[k],nxt[i]=k;
            if(pre[k])
                nxt[pre[k]]=i;
            pre[k]=i;
        }else{
            nxt[i]=nxt[k],pre[i]=k;
            if(nxt[k])
                pre[nxt[k]]=i;
            nxt[k]=i;
        }
    }
    scanf("%d",&m);
    for(int i=1;i<=m;i++){
        int x;
        scanf("%d",&x);
        out[x]=1;
    }
    int p=head;
    while(p){
        if(!out[p])
            printf("%d ",p);
        p=nxt[p];
    }
    return 0;
}
